Here's the XAML and ViewModel you need:

**XAML — ItemsPage.xaml**

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="48,*">
                    <Image Source="{Binding Icon}"
                           WidthRequest="40" HeightRequest="40" />
                    <VerticalStackLayout Grid.Column="1" VerticalOptions="Center">
                        <Label Text="{Binding Name}" FontAttributes="Bold" />
                        <Label Text="{Binding Description}"
                               FontSize="12" TextColor="Gray" />
                    </VerticalStackLayout>
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <ContentView>
                <Label Text="No items found."
                       HorizontalOptions="Center" VerticalOptions="Center" />
            </ContentView>
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

**ViewModel — ItemsViewModel.cs**

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private ObservableCollection<Item> items = new();

    [ObservableProperty]
    private Item? currentItem;

    [ObservableProperty]
    private bool isRefreshing;

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [RelayCommand]
    private async Task Refresh()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            MainThread.BeginInvokeOnMainThread(() =>
            {
                Items.Clear();
                foreach (var item in data)
                    Items.Add(item);
            });
        }
        finally
        {
            IsRefreshing = false; // Must set false to dismiss spinner
        }
    }

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (CurrentItem is null) return;

        await _nav.GoToAsync("DetailPage", new Dictionary<string, object>
        {
            { "Item", CurrentItem }
        });

        CurrentItem = null; // Reset so the same item can be re-selected
    }
}
```

**Key binding relationships:**

| XAML Property | ViewModel Property | Purpose |
|---|---|---|
| `RefreshView.IsRefreshing` | `IsRefreshing` (bool) | Shows/hides the spinner; **must be set to `false`** when done |
| `RefreshView.Command` | `RefreshCommand` | Fires on pull-down; reloads from API |
| `CollectionView.SelectedItem` | `CurrentItem` (TwoWay) | Tracks which item is tapped |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires on selection; navigates to detail page |
| `CollectionView.ItemsSource` | `Items` (ObservableCollection) | Use `ObservableCollection<T>`, never `List<T>` |

**Important notes:**
- Set `CurrentItem = null` after navigation so the same item can be selected again.
- Always set `IsRefreshing = false` in a `finally` block to dismiss the refresh spinner.
- Use `ObservableCollection<T>` so add/remove updates the UI automatically.
- Set `x:DataType` on `DataTemplate` for compiled bindings and better performance.
